// Example: what's the Big-O?
for (var i = 0; i < n; i++) {          // O(n)
  for (var j = 0; j < n; j++) {        // O(n)  nested
    work();                            // O(1)
  }
}
// Total: O(n) * O(n) * O(1) = O(n²)

// Sequential loops:
for (var i = 0; i < n; i++) work();    // O(n)
for (var j = 0; j < n; j++) work();    // O(n)
// Total: O(n) + O(n) = O(2n) = O(n)   (drop constants)

// Nested but different sizes:
for (var i = 0; i < n; i++) {          // O(n)
  for (var j = 0; j < m; j++) work();  // O(m)
}
// Total: O(n * m). If m is a small constant, effectively O(n).

// File: complexity_demo.dart
// Run: dart complexity_demo.dart
import 'dart:math';

void main() {
  for (final n in [1000, 5000, 10000, 20000]) {
    final list = List.generate(n, (i) => Random(42).nextInt(n));

    // O(n²) — check every pair.
    var t = DateTime.now();
    var dups1 = 0;
    for (var i = 0; i < list.length; i++) {
      for (var j = i + 1; j < list.length; j++) {
        if (list[i] == list[j]) { dups1++; break; }
      }
    }
    final ms1 = DateTime.now().difference(t).inMilliseconds;

    // O(n) — hash set.
    t = DateTime.now();
    var dups2 = 0; final seen = <int>{};
    for (final x in list) {
      if (!seen.add(x)) dups2++;
    }
    final ms2 = DateTime.now().difference(t).inMilliseconds;

    print('n=$n | O(n²): $ms1 ms | O(n): $ms2 ms | ratio: ${max(ms2,1)==0?'∞':(ms1 / max(ms2,1)).toStringAsFixed(0)}x');
  }
}

// Typical output (laptop):
// n=1000  | O(n²): 4 ms    | O(n): 1 ms | ratio: 4x
// n=5000  | O(n²): 60 ms   | O(n): 1 ms | ratio: 60x
// n=10000 | O(n²): 240 ms  | O(n): 2 ms | ratio: 120x
// n=20000 | O(n²): 1050 ms | O(n): 3 ms | ratio: 350x
// 
// Notice: as n doubles, O(n²) time roughly QUADRUPLES.
// As n doubles, O(n) time roughly DOUBLES.
// That's Big-O made real."
